#include<bits/stdc++.h>
using namespace std;
void dfs(string zhong,string qian){
    if(!(zhong.size()))return;
    char gen=qian[0];
    int weizhi=zhong.find(gen);
    qian.erase(qian.begin());
    dfs(zhong.substr(0,weizhi),qian.substr(0,weizhi));
    dfs(zhong.substr(weizhi+1),qian.substr(weizhi));
    cout<<gen;
}string z,q;
int main(void){
    cin>>z>>q;
    dfs(z,q);
    return false;
}
